#ifdef BLOCK_SIZE
#else
#define BLOCK_SIZE 16
#endif

#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))

__kernel void hotspot(int iteration,
                      __global float *power,
                      __global float *temp_src,
                      __global float *temp_dst,
                      int grid_cols,
                      int grid_rows,
                      int border_cols,
                      int border_rows,
                      float Cap,
                      float Rx,
                      float Ry,
                      float Rz,
                      float step)
{
    __local float temp_on_cuda[BLOCK_SIZE * BLOCK_SIZE];
    __local float power_on_cuda[BLOCK_SIZE * BLOCK_SIZE];
    __local float temp_t[BLOCK_SIZE * BLOCK_SIZE];

    const float amb_temp = 80.0f;

    const int bx = get_group_id(0);
    const int by = get_group_id(1);

    const int tx = get_local_id(0);
    const int ty = get_local_id(1);

    const int lindex = ty * BLOCK_SIZE + tx;

    const float step_div_Cap = step / Cap;
    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;

    const int small_block_rows = BLOCK_SIZE - iteration * 2;
    const int small_block_cols = BLOCK_SIZE - iteration * 2;

    const int blkY = small_block_rows * by - border_rows;
    const int blkX = small_block_cols * bx - border_cols;
    const int blkYmax = blkY + BLOCK_SIZE - 1;
    const int blkXmax = blkX + BLOCK_SIZE - 1;

    const int yidx = blkY + ty;
    const int xidx = blkX + tx;

    const int loadYidx = yidx;
    const int loadXidx = xidx;
    const int index = grid_cols * loadYidx + loadXidx;

    if (IN_RANGE(loadYidx, 0, grid_rows - 1) && IN_RANGE(loadXidx, 0, grid_cols - 1)) {
        temp_on_cuda[lindex] = temp_src[index];
        power_on_cuda[lindex] = power[index];
    } else {
        temp_on_cuda[lindex] = 0.0f;
        power_on_cuda[lindex] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    const int validYmin = (0 > blkY) ? (-blkY) : 0;
    const int validYmax = (grid_rows - 1 < blkYmax) ? (BLOCK_SIZE - 1 - (blkYmax - grid_rows + 1)) : (BLOCK_SIZE - 1);
    const int validXmin = (0 > blkX) ? (-blkX) : 0;
    const int validXmax = (blkXmax > grid_cols - 1) ? (BLOCK_SIZE - 1 - (blkXmax - grid_cols + 1)) : (BLOCK_SIZE - 1);

    int N = ty - 1;
    int S = ty + 1;
    int W = tx - 1;
    int E = tx + 1;

    N = (validYmin > N) ? validYmin : N;
    S = (S > validYmax) ? validYmax : S;
    W = (W < validXmin) ? validXmin : W;
    E = (validXmax < E) ? validXmax : E;

    int computed = 0;

    for (int i = 0; i < iteration; i++) {
        computed = 0;

        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(tx, validXmin, validXmax) &&
            IN_RANGE(ty, validYmin, validYmax)) {
            computed = 1;

            temp_t[lindex] =
                temp_on_cuda[lindex] +
                step_div_Cap *
                    (power_on_cuda[lindex] +
                     (temp_on_cuda[S * BLOCK_SIZE + tx] + temp_on_cuda[N * BLOCK_SIZE + tx] - 2.0f * temp_on_cuda[lindex]) * Ry_1 +
                     (temp_on_cuda[ty * BLOCK_SIZE + E] + temp_on_cuda[ty * BLOCK_SIZE + W] - 2.0f * temp_on_cuda[lindex]) * Rx_1 +
                     (amb_temp - temp_on_cuda[lindex]) * Rz_1);
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (iteration - 1 == i)
            break;

        if (computed)
            temp_on_cuda[lindex] = temp_t[lindex];

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed) {
        temp_dst[index] = temp_t[lindex];
    }
}
